   502→ * Validate AI response structure matches expected schema
   503→ */
   504→function validateAIResponse(response: Record<string, unknown>): void {
   505→  if (!response || typeof response !== 'object') {
   506→    throw new Error('AI response must be an object');
   507→  }
   508→
   509→  if (!response.primaryCategory || typeof response.primaryCategory !== 'string') {
   510→    throw new Error('AI response must include primaryCategory as string');
   511→  }
   512→
   513→  if (
   514→    response.confidence !== undefined &&
   515→    (typeof response.confidence !== 'number' || response.confidence < 0 || response.confidence > 1)
   516→  ) {
   517→    throw new Error('AI response confidence must be a number between 0 and 1');
   518→  }
   519→
