   340→      thresholdType,
   341→      thresholdUsed: thresholdValue,
   342→      confidenceScore: confidence,
   343→      belowThreshold,
   344→      evaluationReason: `Confidence ${confidence.toFixed(2)} ${belowThreshold ? '<' : '>='} ${thresholdType} threshold ${thresholdValue}`,
   345→    };
   346→
   347→    processingSteps.push(
