   349→    );
   350→
   351→    if (belowThreshold) {
   352→      determinedActions.push('archive');
   353→      actionReasons.push(`Confidence ${confidence.toFixed(2)} below threshold ${thresholdValue}`);
   354→      processingSteps.push('Action: archive (below threshold)');
   355→
   356→      // Mark as read if archiving
   357→      if (actionSettings.markAsReadIfArchived) {
   358→        determinedActions.push('markAsRead');
   359→        actionReasons.push('Mark as read when archiving');
   360→        processingSteps.push('Action: markAsRead (archiving)');
   361→      }
   362→    }
   363→  }
   364→
   365→  // Apply custom category-specific actions
   366→  if (actionSettings.applyCustomActions && config.categoryActions) {
   367→    const allCategories = [assignedLabels.primary, ...assignedLabels.secondary];
   368→
   369→    for (const category of allCategories) {
   370→      const categoryActions = config.categoryActions[category];
   371→      if (categoryActions && Array.isArray(categoryActions)) {
   372→        for (const action of categoryActions) {
   373→          if (!determinedActions.includes(action)) {
   374→            determinedActions.push(action);
   375→            actionReasons.push(`Category ${category} action: ${action}`);
   376→            processingSteps.push(`Action: ${action} (from category ${category})`);
   377→          }
   378→        }
   379→      }
   380→    }
   381→  }
   382→
   383→  const actionReasoning = actionReasons.length > 0 ? actionReasons.join('; ') : 'No actions determined';
   384→
   385→  return { determinedActions, actionReasoning, thresholdEvaluation };
   386→}
