   337→    email: {
   338→      from: formatEmailAddress(email.from),
   339→      subject: email.subject || '',
   340→      body: getEmailBodyText(email),
   341→    },
   342→    candidateCategories: formatObjectForTemplate(candidateCategories),
   343→    detectedAttributes: formatObjectForTemplate(detectedAttributes),
   344→  };
   345→
   346→  // Perform template interpolation using dynamic path resolution
   347→  return interpolateTemplate(template, context);
   348→}
   349→
   350→/**
   351→ * Validate that quoted phrases in evidence actually exist in the email content
   352→ */
   353→function validateEvidenceGrounding(email: EmailMessage, featureExtraction: FeatureExtractionData): EvidenceValidation {
   354→  const emailText = (email.subject + ' ' + getEmailBodyText(email)).toLowerCase();
   355→  const validPhrases: string[] = [];
   356→  const invalidPhrases: string[] = [];
   357→
   358→  // Check all quoted phrases in category enhancements
   359→  for (const [, enhancement] of Object.entries(featureExtraction.categoryEnhancements || {})) {
   360→    if (enhancement.evidence?.quotedPhrases) {
   361→      for (const phrase of enhancement.evidence.quotedPhrases) {
   362→        const normalizedPhrase = phrase.toLowerCase().trim();
   363→        if (normalizedPhrase && emailText.includes(normalizedPhrase)) {
   364→          validPhrases.push(phrase);
   365→        } else if (normalizedPhrase) {
   366→          invalidPhrases.push(phrase);
   367→        }
   368→      }
   369→    }
   370→  }
   371→
   372→  return {
   373→    validPhrases,
   374→    invalidPhrases,
   375→    fabricationDetected: invalidPhrases.length > 0,
   376→  };
   377→}
