/**
 * Final Decision Stage
 *
 * Stage 9 of the EmailCategorizer pipeline. Assigns final labels and determines actions based on
 * AI classification results, confidence thresholds, and label assignment rules.
 *
 * This stage is responsible for:
 * - Assigning final primary and secondary category labels
 * - Filtering secondary labels based on confidence and combination rules
 * - Determining actions (archive, mark as read, custom category actions)
 * - Evaluating archive thresholds based on confidence scores
 * - Generating complete explainability traces with decision rationale
 */

import { z } from 'zod';
import { EmailMessage, ClassificationSession } from '../types';
import { ClassificationResult } from '../types/classification-result';
import { FinalClassification } from './ai-classification';
import { validateEmailInput, validateSessionInput, validateConfigInput } from '../utils/validation';

// Zod schema for final decision configuration
export const FinalDecisionConfigSchema = z.object({
  archiveThresholds: z.object({
    lowImportance: z.number().min(0).max(1),
    mediumImportance: z.number().min(0).max(1),
    highImportance: z.number().min(0).max(1),
  }),
  defaultArchiveThreshold: z.enum(['lowImportance', 'mediumImportance', 'highImportance']),
  labelAssignmentRules: z
    .object({
      maxLabels: z.number().int().min(1),
      minSecondaryConfidence: z.number().min(0).max(1),
      allowedCombinations: z.array(z.string()),
    })
    .optional(),
  actionDetermination: z
    .object({
      archiveIfBelowThreshold: z.boolean(),
      markAsReadIfArchived: z.boolean(),
      applyCustomActions: z.boolean(),
    })
    .optional(),
  categoryActions: z.record(z.array(z.string())).optional(),
});

// Configuration interface for final decision
export interface FinalDecisionConfig {
  archiveThresholds: {
    lowImportance: number;
    mediumImportance: number;
    highImportance: number;
  };
  defaultArchiveThreshold: 'lowImportance' | 'mediumImportance' | 'highImportance';
  labelAssignmentRules?: {
    maxLabels: number;
    minSecondaryConfidence: number;
    allowedCombinations: string[];
  };
  actionDetermination?: {
    archiveIfBelowThreshold: boolean;
    markAsReadIfArchived: boolean;
    applyCustomActions: boolean;
  };
  categoryActions?: Record<string, string[]>;
}

// Assigned labels result
export interface AssignedLabels {
  primary: string;
  secondary: string[];
}

// Threshold evaluation details
export interface ThresholdEvaluation {
  thresholdType: string;
  thresholdUsed: number;
  confidenceScore: number;
  belowThreshold: boolean;
  evaluationReason: string;
}

// Filtered label tracking
export interface FilteredLabel {
  category: string;
  filterReason: string;
  score?: number;
}

// Complete explainability trace for the final decision stage
export interface FinalDecisionExplainabilityTrace {
  aiClassificationInput: FinalClassification;
  labelAssignmentRationale: string;
  actionDeterminationRationale: string;
  thresholdEvaluation?: ThresholdEvaluation;
  filteredLabels?: FilteredLabel[];
  processingSteps: string[];
}

// Complete stage result interface
export interface FinalDecisionResult {
  assignedLabels: AssignedLabels;
  determinedActions: string[];
  actionReasoning: string;
  processingDurationMs: number;
  validationErrors: string[];
  explainabilityTrace: FinalDecisionExplainabilityTrace;
}

/**
 * Final Decision Stage Implementation
 *
 * Assigns final labels and determines actions based on AI classification results
 * and configuration rules, with complete explainability traces.
 *
 * CANONICAL SIGNATURE: (email, session, result, config) => Promise<void>
 * Mutates result object by storing final decision data
 */
export async function finalDecisionStage(
  email: EmailMessage,
  session: ClassificationSession,
  result: ClassificationResult,
  config: FinalDecisionConfig
): Promise<void> {
  const startTime = Date.now();
  const processingSteps: string[] = [];

  // Validate inputs
  validateInputs(email, session, result, config);
  processingSteps.push('Input validation completed');

  // Extract AI classification result from result object
  const aiClassificationResult: FinalClassification = (result as unknown as Record<string, unknown>)
    .aiClassificationResult as FinalClassification;

  // Assign labels based on AI classification and rules
  const { assignedLabels, filteredLabels, labelRationale } = assignLabels(
    aiClassificationResult,
    config,
    processingSteps
  );
  processingSteps.push(
    `Labels assigned: primary=${assignedLabels.primary}, secondary=[${assignedLabels.secondary.join(', ')}]`
  );

  // Determine actions based on confidence thresholds and category rules
  const { determinedActions, actionReasoning } = determineActions(
    assignedLabels,
    aiClassificationResult,
    config,
    processingSteps
  );
  processingSteps.push(`Actions determined: [${determinedActions.join(', ')}]`);

  // Store final decision in explainability trace
  result.explainabilityTrace.finalDecisionReason = labelRationale + '; ' + actionReasoning;

  // Track alternative categories (rejected ones)
  result.explainabilityTrace.alternativeCategories = filteredLabels.map((filtered) => ({
    category: filtered.category,
    score: filtered.score || 0,
    eliminationReason: filtered.filterReason,
  }));

  // Track processing time
  result.explainabilityTrace.stageTimings = result.explainabilityTrace.stageTimings || {};
  result.explainabilityTrace.stageTimings['finalDecision'] = Date.now() - startTime;

  // Mutate result with final labels and actions
  result.primaryCategory = assignedLabels.primary;
  result.secondaryCategories = assignedLabels.secondary;
  result.confidence = aiClassificationResult.confidence;

  // Store determined actions for later use
  (result as unknown as Record<string, unknown>).determinedActions = determinedActions;
}

/**
 * Validate input parameters
 */
function validateInputs(
  email: EmailMessage,
  session: ClassificationSession,
  result: ClassificationResult,
  config: FinalDecisionConfig
): void {
  validateEmailInput(email);
  validateSessionInput(session);
  validateConfigInput(config);

  if (!result) {
    throw new Error('Classification result is required');
  }

  const aiClassificationResult = (result as unknown as Record<string, unknown>).aiClassificationResult;
  if (!aiClassificationResult || typeof aiClassificationResult !== 'object') {
    throw new Error('Invalid AI classification result in result object: object required');
  }

  const aiClassification = aiClassificationResult as FinalClassification;
  if (!aiClassification.primaryCategory || typeof aiClassification.primaryCategory !== 'string') {
    throw new Error('Invalid AI classification: primaryCategory is required');
  }

  if (!config.archiveThresholds || typeof config.archiveThresholds !== 'object') {
    throw new Error('Invalid configuration: archiveThresholds are required');
  }
}

/**
 * Assign labels based on AI classification and label assignment rules
 */
function assignLabels(
  aiClassificationResult: FinalClassification,
  config: FinalDecisionConfig,
  processingSteps: string[]
): {
  assignedLabels: AssignedLabels;
  filteredLabels: FilteredLabel[];
  labelRationale: string;
} {
  const primaryCategory = aiClassificationResult.primaryCategory;
  let secondaryCategories = aiClassificationResult.secondaryCategories || [];
  const filteredLabels: FilteredLabel[] = [];

  processingSteps.push(`Initial labels: primary=${primaryCategory}, secondary=[${secondaryCategories.join(', ')}]`);

  // Apply label assignment rules if configured
  if (config.labelAssignmentRules) {
    const rules = config.labelAssignmentRules;

    // Filter by confidence threshold if categoryScores are available
    if (aiClassificationResult.categoryScores && rules.minSecondaryConfidence) {
      const primaryScore = aiClassificationResult.categoryScores[primaryCategory] || 0;

      secondaryCategories = secondaryCategories.filter((category) => {
        const categoryScore = aiClassificationResult.categoryScores![category] || 0;
        // Handle edge case where primary has no score but secondary does
        const relativeConfidence = primaryScore > 0 ? categoryScore / primaryScore : categoryScore > 0 ? 1.0 : 0;

        if (relativeConfidence < rules.minSecondaryConfidence) {
          filteredLabels.push({
            category,
            filterReason: `Relative confidence ${relativeConfidence.toFixed(2)} below threshold ${rules.minSecondaryConfidence}`,
            score: categoryScore,
          });
          processingSteps.push(
            `Filtered ${category}: confidence too low (${relativeConfidence.toFixed(2)} < ${rules.minSecondaryConfidence})`
          );
          return false;
        }

        return true;
      });
    }

    // Filter by allowed combinations
    if (rules.allowedCombinations && rules.allowedCombinations.length > 0) {
      secondaryCategories = secondaryCategories.filter((category) => {
        const combination = `${primaryCategory}+${category}`;
        const reverseCombination = `${category}+${primaryCategory}`;

        // Check if this specific combination is allowed
        const isAllowed =
          rules.allowedCombinations.includes(combination) || rules.allowedCombinations.includes(reverseCombination);

        if (!isAllowed) {
          filteredLabels.push({
            category,
            filterReason: `Combination ${combination} not in allowed list`,
          });
          processingSteps.push(`Filtered ${category}: combination with ${primaryCategory} not allowed`);
        }

        return isAllowed;
      });
    }

    // Limit to maxLabels (subtract 1 for primary)
    if (rules.maxLabels && secondaryCategories.length > rules.maxLabels - 1) {
      const sortedSecondaryCategories = [...secondaryCategories];

      // Sort by score if available
      if (aiClassificationResult.categoryScores) {
        sortedSecondaryCategories.sort((a, b) => {
          const scoreA = aiClassificationResult.categoryScores![a] || 0;
          const scoreB = aiClassificationResult.categoryScores![b] || 0;
          return scoreB - scoreA;
        });
      }

      const maxSecondary = rules.maxLabels - 1;
      const removedCategories = sortedSecondaryCategories.slice(maxSecondary);

      removedCategories.forEach((category) => {
        filteredLabels.push({
          category,
          filterReason: `Exceeded maxLabels limit of ${rules.maxLabels}`,
          score: aiClassificationResult.categoryScores?.[category],
        });
      });

      secondaryCategories = sortedSecondaryCategories.slice(0, maxSecondary);
      processingSteps.push(`Limited secondary labels to ${maxSecondary} (maxLabels=${rules.maxLabels})`);
    }
  }

  const assignedLabels: AssignedLabels = {
    primary: primaryCategory,
    secondary: secondaryCategories,
  };

  let labelRationale = `Assigned primary label: ${primaryCategory}`;
  if (secondaryCategories.length > 0) {
    labelRationale += `, secondary labels: [${secondaryCategories.join(', ')}]`;
  }
  if (filteredLabels.length > 0) {
    labelRationale += `. Filtered ${filteredLabels.length} labels based on rules`;
  }

  return { assignedLabels, filteredLabels, labelRationale };
}

/**
 * Determine actions based on confidence thresholds and category rules
 */
function determineActions(
  assignedLabels: AssignedLabels,
  aiClassificationResult: FinalClassification,
  config: FinalDecisionConfig,
  processingSteps: string[]
): {
  determinedActions: string[];
  actionReasoning: string;
  thresholdEvaluation?: ThresholdEvaluation;
} {
  const determinedActions: string[] = [];
  const actionReasons: string[] = [];

  // Get action determination settings with defaults
  const actionSettings = config.actionDetermination || {
    archiveIfBelowThreshold: true,
    markAsReadIfArchived: false,
    applyCustomActions: false,
  };

  // Evaluate archive threshold
  let thresholdEvaluation: ThresholdEvaluation | undefined;

  if (actionSettings.archiveIfBelowThreshold) {
    const thresholdType = config.defaultArchiveThreshold;
    const thresholdValue = config.archiveThresholds[thresholdType];
    const confidence = aiClassificationResult.confidence;
    const belowThreshold = confidence < thresholdValue;

    thresholdEvaluation = {
      thresholdType,
      thresholdUsed: thresholdValue,
      confidenceScore: confidence,
      belowThreshold,
      evaluationReason: `Confidence ${confidence.toFixed(2)} ${belowThreshold ? '<' : '>='} ${thresholdType} threshold ${thresholdValue}`,
    };

    processingSteps.push(
      `Threshold evaluation: ${confidence.toFixed(2)} ${belowThreshold ? 'below' : 'above'} ${thresholdType} (${thresholdValue})`
    );

    if (belowThreshold) {
      determinedActions.push('archive');
      actionReasons.push(`Confidence ${confidence.toFixed(2)} below threshold ${thresholdValue}`);
      processingSteps.push('Action: archive (below threshold)');

      // Mark as read if archiving
      if (actionSettings.markAsReadIfArchived) {
        determinedActions.push('markAsRead');
        actionReasons.push('Mark as read when archiving');
        processingSteps.push('Action: markAsRead (archiving)');
      }
    }
  }

  // Apply custom category-specific actions
  if (actionSettings.applyCustomActions && config.categoryActions) {
    const allCategories = [assignedLabels.primary, ...assignedLabels.secondary];

    for (const category of allCategories) {
      const categoryActions = config.categoryActions[category];
      if (categoryActions && Array.isArray(categoryActions)) {
        for (const action of categoryActions) {
          if (!determinedActions.includes(action)) {
            determinedActions.push(action);
            actionReasons.push(`Category ${category} action: ${action}`);
            processingSteps.push(`Action: ${action} (from category ${category})`);
          }
        }
      }
    }
  }

  const actionReasoning = actionReasons.length > 0 ? actionReasons.join('; ') : 'No actions determined';

  return { determinedActions, actionReasoning, thresholdEvaluation };
}

