/**
 * ClassificationResult entity with explainability
 *
 * Core classification result with preserved sophistication and enhanced
 * explainability for the 9-stage classification pipeline.
 */

import { ExplainabilityTrace } from './explainability-trace';
import { ScoreBreakdown } from './score-breakdown';
import { AttributeContext } from './attribute-context';

/**
 * Intermediate types for multi-label selection and AI routing stages
 */

export interface SelectedLabel {
  category: string;
  subtype: string | null;
  confidence: number;
  score: number;
  isPrimary: boolean;
  labelOrder: number;
  selectionRationale: string;
}

/**
 * Pipeline-oriented selection summary
 * Used during pipeline execution and by persistence layer
 */
export interface PipelineSelectionSummary {
  totalLabels: number;
  primaryCategory: string | null;
  confidenceRange: [number, number];
  selectionMethod: string;
  needsAi: boolean;
  topCategories?: Array<{ category: string; score: number }>;
}

export interface CandidateScore {
  score: number;
  confidence: number;
  rationale?: string;
  decision?: 'selected' | 'candidate' | 'rejected';
  hardAssertion?: boolean;
}

export interface ClassificationResult {
  id: string; // UUID
  emailId: string; // Foreign key to EmailMessage
  sessionId: string; // Foreign key to ClassificationSession

  // Classification results (database-oriented - flattened for persistence)
  primaryCategory: string;
  secondaryCategories: string[];
  confidence: number; // 0.0 - 1.0

  // Enhanced explainability
  explainabilityTrace: ExplainabilityTrace;
  scoreBreakdown: ScoreBreakdown;
  attributeContext: AttributeContext;

  // Processing metadata
  processedAt: Date;
  processingDurationMs: number;
  aiRoutingUsed: boolean;

  // Parallel processing context
  batchPosition: number;
  parallelStageResults: ParallelStageResult[];

  // Pipeline-oriented fields (rich execution metadata)
  // NOTE: These fields provide detailed classification context during pipeline execution.
  // The flattened fields above (primaryCategory, secondaryCategories, confidence) are
  // derived from these for database persistence.
  selectedLabels: SelectedLabel[]; // Detailed label selection with rationale
  candidateScores: Record<string, CandidateScore>; // All category scores from pipeline
  selectionSummary: PipelineSelectionSummary; // Pipeline execution summary
  needsAiClassification: boolean; // AI routing decision from pipeline
}

export interface ParallelStageResult {
  stageId: string;
  stageName: string;
  executionTimeMs: number;
  parallelWithStages: string[];
  dependentOnStages: string[];
  memoryUsageMB?: number;
  cacheHitsCount: number;
  errorCount: number;
}

/**
 * Classification confidence levels with business semantics
 */
export enum ConfidenceLevel {
  HIGH = 'high', // > 0.8 - Can proceed without review
  MEDIUM = 'medium', // 0.5 - 0.8 - May need review for important actions
  LOW = 'low', // 0.2 - 0.5 - Needs review or AI assistance
  UNCERTAIN = 'uncertain', // < 0.2 - Requires manual classification
}

/**
 * Category assignment types for multi-label support
 */
export enum CategoryAssignmentType {
  PRIMARY = 'primary', // Main category assignment
  SECONDARY = 'secondary', // Additional relevant category
  DISAMBIGUATION = 'disambiguation', // Category used for tie-breaking
  AI_SUGGESTED = 'aiSuggested', // Category suggested by AI routing
}

/**
 * Enhanced classification result with detailed reasoning
 */
export interface DetailedClassificationResult extends ClassificationResult {
  confidenceLevel: ConfidenceLevel;
  categoryAssignments: CategoryAssignment[];
  alternativeCategories: AlternativeCategory[];
  classificationReasons: string[];
  requiredActions: RequiredAction[];
}

export interface CategoryAssignment {
  category: string;
  subtype?: string;
  confidence: number;
  assignmentType: CategoryAssignmentType;
  reasoning: string;
  sourceStages: string[]; // Which pipeline stages contributed
}

export interface AlternativeCategory {
  category: string;
  score: number;
  eliminationReason: string;
  closenessScore: number; // How close this was to being selected
}

export interface RequiredAction {
  action: 'manualReview' | 'aiClassification' | 'userFeedback' | 'reprocessWithConfig';
  priority: 'low' | 'medium' | 'high';
  reason: string;
  suggestedBy: string; // Which stage suggested this action
}

